// - baseCallback must be an absolute URL.
// - redirectPath may be empty, a relative path, or an absolute URL with the same scheme+host as baseCallback.
// The returned callback URL is baseCallback with an added/updated "redirect" query parameter.
func buildCallbackURL(baseCallback, redirectPath string) (string, error) {
	baseU, err := url.Parse(baseCallback)
	if err != nil || baseU.Scheme == "" || baseU.Host == "" {
