			if !strings.HasPrefix(target, "/") {
				target = "/" + target
			}
			target = path.Clean(target)
			if target == "." {
				target = "/"
			}
		}
	}

	cb := *baseU
	q := cb.Query()
	if target != "" {
		q.Set("redirect", target)
	}
	cb.RawQuery = q.Encode()
	return cb.String(), nil
