import (
	"crypto/rand"
	"encoding/base64"
	"errors"
	"net/http"
	"net/url"
	"path"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	if w == nil || r == nil {
		return "", errors.New("nil http request/response")
	}

	state, err := newState(32)
	if err != nil {
		return "", err
	}

	// Build a safe callback URL based on the configured RedirectURL, allowing only path/query override.
	cb, err := buildCallbackURL(OAuthConfig.RedirectURL, redirectPath)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = cb

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   r.TLS != nil,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

func newState(n int) (string, error) {
	if n <= 0 {
		n = 32
	}
	b := make([]byte, n)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	// URL-safe, no padding
	return base64.RawURLEncoding.EncodeToString(b), nil
}

// buildCallbackURL takes the configured RedirectURL as a base and applies redirectPath as:
// - If redirectPath is an absolute URL: it must match scheme+host of base.
// - If redirectPath is a relative path/query: it is joined with base path and query applied.
func buildCallbackURL(baseRedirectURL, redirectPath string) (string, error) {
	baseU, err := url.Parse(baseRedirectURL)
	if err != nil || baseU.Scheme == "" || baseU.Host == "" {
		return "", errors.New("invalid base RedirectURL")
	}

	if strings.TrimSpace(redirectPath) == "" {
		return baseU.String(), nil
	}

	u, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	// Absolute URL: only allow same origin as base.
	if u.IsAbs() {
		if !strings.EqualFold(u.Scheme, baseU.Scheme) || !strings.EqualFold(u.Host, baseU.Host) {
			return "", errors.New("redirect URL origin not allowed")
		}
		return u.String(), nil
	}

	// Relative: apply path + query + fragment onto base origin.
	out := *baseU
	if u.Path != "" {
		// If redirectPath starts with "/", treat as absolute path on same host.
		if strings.HasPrefix(u.Path, "/") {
			out.Path = path.Clean(u.Path)
		} else {
			// Otherwise join relative to base path directory.
			dir := path.Dir(out.Path)
			out.Path = path.Clean(path.Join(dir, u.Path))
		}
	}
	if u.RawQuery != "" {
		out.RawQuery = u.RawQuery
	}
	if u.Fragment != "" {
		out.Fragment = u.Fragment
	}
	return out.String(), nil
}

