			http.Error(w, "invalid state", http.StatusBadRequest)
			return
		}

		returnTo := "/"
		if c, err := r.Cookie("oauth_return_to"); err == nil && c.Value != "" {
			if v, err := url.QueryUnescape(c.Value); err == nil && v != "" {
				returnTo = v
			}
		}

		// In a real app, exchange code for token:
		// tok, err := OAuthConfig.Exchange(r.Context(), code)

		fmt.Fprintf(w, "OAuth callback received.\ncode=%s\nreturn_to=%s\n", code, returnTo)
	})

	addr := ":8080"
	fmt.Println("Listening on", addr)
	_ = http.ListenAndServe(addr, mux)
}

